#include <bits/stdc++.h>
using namespace std;

struct Vec3{
    double x,y,z;
};
struct Face{int a,b,c;};

static inline Vec3 operator+(const Vec3&a,const Vec3&b){return {a.x+b.x,a.y+b.y,a.z+b.z};}
static inline Vec3 operator-(const Vec3&a,const Vec3&b){return {a.x-b.x,a.y-b.y,a.z-b.z};}
static inline Vec3 operator*(const Vec3&a,double s){return {a.x*s,a.y*s,a.z*s};}
static inline Vec3 operator/(const Vec3&a,double s){return {a.x/s,a.y/s,a.z/s};}
static inline double dotv(const Vec3&a,const Vec3&b){return a.x*b.x+a.y*b.y+a.z*b.z;}
static inline Vec3 crossv(const Vec3&a,const Vec3&b){return {a.y*b.z-a.z*b.y,a.z*b.x-a.x*b.z,a.x*b.y-a.y*b.x};}
static inline double norm2(const Vec3&a){return dotv(a,a);} 
static inline double normv(const Vec3&a){return sqrt(norm2(a));}
static inline Vec3 normed(Vec3 a){double n=normv(a); if(n<=0) return {0,0,0}; return a/n;}

vector<Vec3> Pin;
vector<Face> Fin;
int N,M;
Vec3 BBmn, BBmx, BBC;
double DIAG=1.0, HTOL=1.0;
chrono::steady_clock::time_point T0;
static inline double elapsed(){return chrono::duration<double>(chrono::steady_clock::now()-T0).count();}

static void readInput(){
    ios::sync_with_stdio(false); cin.tie(nullptr);
    cin>>N>>M;
    Pin.resize(N); Fin.resize(M);
    BBmn={1e100,1e100,1e100}; BBmx={-1e100,-1e100,-1e100};
    char ch;
    for(int i=0;i<N;i++){
        cin>>ch>>Pin[i].x>>Pin[i].y>>Pin[i].z;
        BBmn.x=min(BBmn.x,Pin[i].x); BBmn.y=min(BBmn.y,Pin[i].y); BBmn.z=min(BBmn.z,Pin[i].z);
        BBmx.x=max(BBmx.x,Pin[i].x); BBmx.y=max(BBmx.y,Pin[i].y); BBmx.z=max(BBmx.z,Pin[i].z);
    }
    for(int i=0;i<M;i++){
        cin>>ch>>Fin[i].a>>Fin[i].b>>Fin[i].c;
        --Fin[i].a;--Fin[i].b;--Fin[i].c;
    }
    BBC=(BBmn+BBmx)*0.5;
    DIAG=normv(BBmx-BBmn); if(!(DIAG>0)) DIAG=1.0;
    HTOL=0.0492*DIAG;
}

static inline long long edgeKey(int a,int b){ if(a>b) swap(a,b); return ( (long long)(unsigned int)a<<32 ) | (unsigned int)b; }
static inline array<int,3> triKey(Face f){ array<int,3> a={f.a,f.b,f.c}; sort(a.begin(),a.end()); return a; }
static inline double faceArea2(const vector<Vec3>&V, const Face&f){return norm2(crossv(V[f.b]-V[f.a],V[f.c]-V[f.a]));}

static void orientOut(vector<Vec3>&V, Face &f, const Vec3& ref){
    Vec3 n=crossv(V[f.b]-V[f.a], V[f.c]-V[f.a]);
    Vec3 c=(V[f.a]+V[f.b]+V[f.c])/3.0;
    if(dotv(n,c-ref)<0) swap(f.b,f.c);
}
static void addFace(vector<Vec3>&V, vector<Face>&F, int a,int b,int c, const Vec3&ref){
    if(a==b||a==c||b==c) return;
    Face f{a,b,c}; orientOut(V,f,ref); F.push_back(f);
}

struct GridHash{
    Vec3 mn; double cell; unordered_map<long long, vector<int>> h;
    static long long pack(int x,int y,int z){
        const long long B=1048576LL, O=524288LL;
        return ((long long)(x+O)*B + (y+O))*B + (z+O);
    }
    GridHash(){}
    GridHash(const vector<Vec3>&P,double c){init(P,c);} 
    void init(const vector<Vec3>&P,double c){
        cell=max(c,1e-12); mn={1e100,1e100,1e100};
        for(auto&p:P){mn.x=min(mn.x,p.x);mn.y=min(mn.y,p.y);mn.z=min(mn.z,p.z);}        
        h.reserve(P.size()*2+10);
        for(int i=0;i<(int)P.size();++i){int x,y,z; idx(P[i],x,y,z); h[pack(x,y,z)].push_back(i);}    }
    void idx(const Vec3&p,int&x,int&y,int&z) const{
        x=(int)floor((p.x-mn.x)/cell); y=(int)floor((p.y-mn.y)/cell); z=(int)floor((p.z-mn.z)/cell);
    }
    bool hasNear(const vector<Vec3>&P,const Vec3&q,double r) const{
        int X,Y,Z; idx(q,X,Y,Z); double r2=r*r;
        for(int dx=-1;dx<=1;dx++) for(int dy=-1;dy<=1;dy++) for(int dz=-1;dz<=1;dz++){
            auto it=h.find(pack(X+dx,Y+dy,Z+dz)); if(it==h.end()) continue;
            for(int id:it->second) if(norm2(P[id]-q)<=r2) return true;
        }
        return false;
    }
};

static bool symmetricVertexCheck(const vector<Vec3>&V,double tol){
    if(V.empty()) return false;
    GridHash ghOut(V,tol);
    for(const Vec3&p:Pin) if(!ghOut.hasNear(V,p,tol)) return false;
    GridHash ghIn(Pin,tol);
    for(const Vec3&p:V) if(!ghIn.hasNear(Pin,p,tol)) return false;
    return true;
}

static bool closedEdgeCheck(const vector<Vec3>&V,const vector<Face>&F){
    if(V.empty()||F.empty()||V.size()>(size_t)N) return false;
    double eps=max(1e-28,1e-24*DIAG*DIAG);
    unordered_map<long long,int> cnt; cnt.reserve(F.size()*4+10);
    unordered_set<unsigned long long> dup; dup.reserve(F.size()*2+10);
    auto packTri=[&](array<int,3>a)->unsigned long long{
        return ((unsigned long long)(unsigned int)a[0]<<42)^((unsigned long long)(unsigned int)a[1]<<21)^(unsigned int)a[2];
    };
    for(const Face&f:F){
        if(f.a<0||f.b<0||f.c<0||f.a>=(int)V.size()||f.b>=(int)V.size()||f.c>=(int)V.size()) return false;
        if(f.a==f.b||f.a==f.c||f.b==f.c) return false;
        if(faceArea2(V,f)<=eps) return false;
        auto tk=triKey(f); unsigned long long pk=packTri(tk); if(dup.count(pk)) return false; dup.insert(pk);
        cnt[edgeKey(f.a,f.b)]++; cnt[edgeKey(f.b,f.c)]++; cnt[edgeKey(f.c,f.a)]++;
    }
    for(auto &kv:cnt) if(kv.second!=2) return false;
    return true;
}

static bool acceptCandidate(const vector<Vec3>&V,const vector<Face>&F){
    return V.size()<=Pin.size() && closedEdgeCheck(V,F) && symmetricVertexCheck(V,HTOL);
}

static void printMesh(const vector<Vec3>&V,const vector<Face>&F){
    cout.setf(ios::fixed); cout<<setprecision(10);
    cout<<V.size()<<" "<<F.size()<<"\n";
    for(auto&p:V) cout<<"v "<<p.x<<" "<<p.y<<" "<<p.z<<"\n";
    for(auto&f:F) cout<<"f "<<f.a+1<<" "<<f.b+1<<" "<<f.c+1<<"\n";
}

static void printOriginal(){ printMesh(Pin,Fin); }

// AABB box remesh with grid vertices. It is only used after a strict vertex-Hausdorff check.
static bool tryBox(vector<Vec3>&V, vector<Face>&F){
    if(N<1500) return false;
    double dx=BBmx.x-BBmn.x, dy=BBmx.y-BBmn.y, dz=BBmx.z-BBmn.z;
    if(min({dx,dy,dz})<1e-8*DIAG) return false;
    int bad=0; double sum=0; int st=max(1,N/200000);
    for(int i=0;i<N;i+=st){
        const Vec3&p=Pin[i];
        double d=min({fabs(p.x-BBmn.x),fabs(p.x-BBmx.x),fabs(p.y-BBmn.y),fabs(p.y-BBmx.y),fabs(p.z-BBmn.z),fabs(p.z-BBmx.z)});
        sum+=d; if(d>0.012*DIAG) bad++;
    }
    int samples=(N+st-1)/st;
    if(bad*1000>samples*3 || sum>samples*0.0045*DIAG) return false;
    double step=max(HTOL*0.72, DIAG*0.015);
    int nx=max(1,(int)ceil(dx/step)); int ny=max(1,(int)ceil(dy/step)); int nz=max(1,(int)ceil(dz/step));
    auto key=[&](int i,int j,int k)->long long{return ((long long)i*(ny+1)+j)*(nz+1)+k;};
    unordered_map<long long,int> id; id.reserve((nx+1)*(ny+1)*2+(nx+1)*(nz+1)*2+(ny+1)*(nz+1)*2);
    auto get=[&](int i,int j,int k)->int{
        long long kk=key(i,j,k); auto it=id.find(kk); if(it!=id.end()) return it->second;
        Vec3 p{BBmn.x+dx*(double)i/nx, BBmn.y+dy*(double)j/ny, BBmn.z+dz*(double)k/nz};
        int r=(int)V.size(); V.push_back(p); id[kk]=r; return r;
    };
    V.clear(); F.clear(); Vec3 ref=BBC;
    for(int i=0;i<nx;i++) for(int j=0;j<ny;j++){
        int a=get(i,j,0),b=get(i+1,j,0),c=get(i+1,j+1,0),d=get(i,j+1,0); addFace(V,F,a,b,c,ref); addFace(V,F,a,c,d,ref);
        a=get(i,j,nz);b=get(i+1,j,nz);c=get(i+1,j+1,nz);d=get(i,j+1,nz); addFace(V,F,a,c,b,ref); addFace(V,F,a,d,c,ref);
    }
    for(int i=0;i<nx;i++) for(int k=0;k<nz;k++){
        int a=get(i,0,k),b=get(i+1,0,k),c=get(i+1,0,k+1),d=get(i,0,k+1); addFace(V,F,a,b,c,ref); addFace(V,F,a,c,d,ref);
        a=get(i,ny,k);b=get(i+1,ny,k);c=get(i+1,ny,k+1);d=get(i,ny,k+1); addFace(V,F,a,c,b,ref); addFace(V,F,a,d,c,ref);
    }
    for(int j=0;j<ny;j++) for(int k=0;k<nz;k++){
        int a=get(0,j,k),b=get(0,j+1,k),c=get(0,j+1,k+1),d=get(0,j,k+1); addFace(V,F,a,b,c,ref); addFace(V,F,a,c,d,ref);
        a=get(nx,j,k);b=get(nx,j+1,k);c=get(nx,j+1,k+1);d=get(nx,j,k+1); addFace(V,F,a,c,b,ref); addFace(V,F,a,d,c,ref);
    }
    return V.size()<Pin.size()*7/10 && acceptCandidate(V,F);
}

static void makeIcosa(vector<Vec3>&V, vector<Face>&F){
    V.clear(); F.clear();
    double t=(1.0+sqrt(5.0))*0.5;
    vector<Vec3> base={{-1,t,0},{1,t,0},{-1,-t,0},{1,-t,0},{0,-1,t},{0,1,t},{0,-1,-t},{0,1,-t},{t,0,-1},{t,0,1},{-t,0,-1},{-t,0,1}};
    for(auto&p:base) V.push_back(normed(p));
    int fa[20][3]={{0,11,5},{0,5,1},{0,1,7},{0,7,10},{0,10,11},{1,5,9},{5,11,4},{11,10,2},{10,7,6},{7,1,8},{3,9,4},{3,4,2},{3,2,6},{3,6,8},{3,8,9},{4,9,5},{2,4,11},{6,2,10},{8,6,7},{9,8,1}};
    for(auto &x:fa) F.push_back({x[0],x[1],x[2]});
}
static void subdivSphere(vector<Vec3>&V, vector<Face>&F){
    map<pair<int,int>,int> mid;
    auto getmid=[&](int a,int b)->int{
        if(a>b) swap(a,b); pair<int,int> k={a,b}; auto it=mid.find(k); if(it!=mid.end()) return it->second;
        int id=V.size(); V.push_back(normed((V[a]+V[b])*0.5)); mid[k]=id; return id;
    };
    vector<Face> NF; NF.reserve(F.size()*4);
    for(auto f:F){int ab=getmid(f.a,f.b), bc=getmid(f.b,f.c), ca=getmid(f.c,f.a); NF.push_back({f.a,ab,ca}); NF.push_back({f.b,bc,ab}); NF.push_back({f.c,ca,bc}); NF.push_back({ab,bc,ca});}
    F.swap(NF);
}

static bool tryEllipsoid(vector<Vec3>&V, vector<Face>&F){
    if(N<3500) return false;
    Vec3 r={(BBmx.x-BBmn.x)*0.5,(BBmx.y-BBmn.y)*0.5,(BBmx.z-BBmn.z)*0.5};
    if(min({r.x,r.y,r.z})<0.08*DIAG) return false;
    int st=max(1,N/220000), bad=0, cnt=0; double sum=0, mxerr=0;
    for(int i=0;i<N;i+=st){
        Vec3 q=Pin[i]-BBC;
        double s=sqrt((q.x*q.x)/(r.x*r.x)+(q.y*q.y)/(r.y*r.y)+(q.z*q.z)/(r.z*r.z));
        double e=fabs(s-1.0); sum+=e; mxerr=max(mxerr,e); if(e>0.055) bad++; cnt++;
    }
    if(cnt<100 || bad*100>cnt*2 || sum/cnt>0.018 || mxerr>0.14) return false;
    int sub = (N>120000?4:3);
    makeIcosa(V,F); for(int i=0;i<sub;i++) subdivSphere(V,F);
    if(V.size()>=Pin.size()*8/10) return false;
    for(auto &p:V){
        Vec3 d=normed(p);
        double den=(d.x*d.x)/(r.x*r.x)+(d.y*d.y)/(r.y*r.y)+(d.z*d.z)/(r.z*r.z);
        double t=1.0/sqrt(max(den,1e-100));
        p=BBC+d*t;
    }
    for(auto &f:F) orientOut(V,f,BBC);
    return acceptCandidate(V,F);
}

static Vec3 fromAxis(int ax, double u,double v,double w){
    if(ax==0) return {w,u,v};
    if(ax==1) return {u,w,v};
    return {u,v,w};
}
static void toAxis(const Vec3&p,int ax,double&u,double&v,double&w){
    if(ax==0){w=p.x;u=p.y;v=p.z;} else if(ax==1){u=p.x;w=p.y;v=p.z;} else {u=p.x;v=p.y;w=p.z;}
}

static bool tryCylinderAxis(int ax, vector<Vec3>&V, vector<Face>&F){
    double mnU=1e100,mxU=-1e100,mnV=1e100,mxV=-1e100,mnW=1e100,mxW=-1e100;
    for(auto&p:Pin){double u,v,w;toAxis(p,ax,u,v,w);mnU=min(mnU,u);mxU=max(mxU,u);mnV=min(mnV,v);mxV=max(mxV,v);mnW=min(mnW,w);mxW=max(mxW,w);}    
    double cu=(mnU+mxU)*0.5, cv=(mnV+mxV)*0.5, h=mxW-mnW;
    double R=0; for(auto&p:Pin){double u,v,w;toAxis(p,ax,u,v,w);R=max(R,hypot(u-cu,v-cv));}
    if(R<0.08*DIAG||h<0.08*DIAG) return false;
    int st=max(1,N/200000), cnt=0,bad=0; double sum=0;
    for(int i=0;i<N;i+=st){double u,v,w;toAxis(Pin[i],ax,u,v,w); double rr=hypot(u-cu,v-cv); double side=fabs(rr-R); double cap=min(fabs(w-mnW),fabs(w-mxW)); double d=min(side,cap); sum+=d; if(d>0.018*DIAG) bad++; cnt++;}
    if(cnt<100 || bad*100>cnt*2 || sum/cnt>0.0065*DIAG) return false;
    double step=max(HTOL*0.68,DIAG*0.014);
    int nt=max(12,(int)ceil(2*M_PI*R/step)); nt=min(nt,180);
    int nz=max(1,(int)ceil(h/step)); nz=min(nz,140);
    int nr=max(1,(int)ceil(R/step)); nr=min(nr,80);
    V.clear(); F.clear(); Vec3 ref=BBC;
    vector<vector<int>> side(nz+1, vector<int>(nt));
    for(int k=0;k<=nz;k++){double w=mnW+h*(double)k/nz; for(int t=0;t<nt;t++){double a=2*M_PI*t/nt; side[k][t]=V.size(); V.push_back(fromAxis(ax,cu+R*cos(a),cv+R*sin(a),w));}}
    for(int k=0;k<nz;k++) for(int t=0;t<nt;t++){int t2=(t+1)%nt; addFace(V,F,side[k][t],side[k][t2],side[k+1][t2],ref); addFace(V,F,side[k][t],side[k+1][t2],side[k+1][t],ref);}    
    for(int capi=0;capi<2;capi++){
        double w=capi?mxW:mnW; int outerK=capi?nz:0;
        int center=V.size(); V.push_back(fromAxis(ax,cu,cv,w));
        vector<vector<int>> ring(nr+1, vector<int>(nt));
        for(int t=0;t<nt;t++) ring[nr][t]=side[outerK][t];
        for(int rix=1;rix<nr;rix++){double rad=R*(double)rix/nr; for(int t=0;t<nt;t++){double a=2*M_PI*t/nt; ring[rix][t]=V.size(); V.push_back(fromAxis(ax,cu+rad*cos(a),cv+rad*sin(a),w));}}
        for(int t=0;t<nt;t++){int t2=(t+1)%nt; addFace(V,F,center,ring[1][t],ring[1][t2],ref);}        
        for(int rix=1;rix<nr;rix++) for(int t=0;t<nt;t++){int t2=(t+1)%nt; addFace(V,F,ring[rix][t],ring[rix+1][t],ring[rix+1][t2],ref); addFace(V,F,ring[rix][t],ring[rix+1][t2],ring[rix][t2],ref);}    
    }
    return V.size()<Pin.size()*7/10 && acceptCandidate(V,F);
}
static bool tryCylinder(vector<Vec3>&V, vector<Face>&F){
    if(N<3000) return false;
    for(int ax=0;ax<3;ax++){ if(tryCylinderAxis(ax,V,F)) return true; }
    return false;
}

static bool tryTorusAxis(int ax, vector<Vec3>&V, vector<Face>&F){
    vector<double> rho; rho.reserve(N); double mnW=1e100,mxW=-1e100; double cu=0,cv=0;
    double mnU=1e100,mxU=-1e100,mnV=1e100,mxV=-1e100;
    for(auto&p:Pin){double u,v,w;toAxis(p,ax,u,v,w);mnU=min(mnU,u);mxU=max(mxU,u);mnV=min(mnV,v);mxV=max(mxV,v);mnW=min(mnW,w);mxW=max(mxW,w);}    
    cu=(mnU+mxU)*0.5; cv=(mnV+mxV)*0.5;
    double Rmean=0; for(auto&p:Pin){double u,v,w;toAxis(p,ax,u,v,w); double rr=hypot(u-cu,v-cv); Rmean+=rr;} Rmean/=max(1,N);
    double rmean=0; for(auto&p:Pin){double u,v,w;toAxis(p,ax,u,v,w); double rr=hypot(u-cu,v-cv); rmean+=hypot(rr-Rmean,w-(mnW+mxW)*0.5);} rmean/=max(1,N);
    if(Rmean<0.12*DIAG||rmean<0.025*DIAG||rmean>0.45*Rmean) return false;
    double cw=(mnW+mxW)*0.5;
    int st=max(1,N/200000),cnt=0,bad=0; double sum=0;
    for(int i=0;i<N;i+=st){double u,v,w;toAxis(Pin[i],ax,u,v,w); double rr=hypot(u-cu,v-cv); double e=fabs(hypot(rr-Rmean,w-cw)-rmean); sum+=e; if(e>0.016*DIAG) bad++; cnt++;}
    if(cnt<100 || bad*100>cnt*2 || sum/cnt>0.006*DIAG) return false;
    double step=max(HTOL*0.70,DIAG*0.014);
    int nu=max(16,(int)ceil(2*M_PI*Rmean/step)); int nv=max(8,(int)ceil(2*M_PI*rmean/step));
    nu=min(nu,220); nv=min(nv,120);
    if((long long)nu*nv>=N*7LL/10) return false;
    V.clear(); F.clear(); V.reserve(nu*nv);
    for(int i=0;i<nu;i++){double uang=2*M_PI*i/nu; for(int j=0;j<nv;j++){double vang=2*M_PI*j/nv; double rr=Rmean+rmean*cos(vang); double u=cu+rr*cos(uang), v=cv+rr*sin(uang), w=cw+rmean*sin(vang); V.push_back(fromAxis(ax,u,v,w));}}
    auto id=[&](int i,int j){i%=nu; if(i<0)i+=nu; j%=nv; if(j<0)j+=nv; return i*nv+j;};
    for(int i=0;i<nu;i++) for(int j=0;j<nv;j++){
        int a=id(i,j),b=id(i+1,j),c=id(i+1,j+1),d=id(i,j+1);
        Face f1{a,b,c},f2{a,c,d};
        auto fix=[&](Face &f){
            Vec3 p=(V[f.a]+V[f.b]+V[f.c])/3.0; double u,v,w;toAxis(p,ax,u,v,w); double ang=atan2(v-cv,u-cu); Vec3 tube=fromAxis(ax,cu+Rmean*cos(ang),cv+Rmean*sin(ang),cw); Vec3 want=p-tube; Vec3 n=crossv(V[f.b]-V[f.a],V[f.c]-V[f.a]); if(dotv(n,want)<0) swap(f.b,f.c);
        };
        fix(f1); fix(f2); F.push_back(f1); F.push_back(f2);
    }
    return acceptCandidate(V,F);
}
static bool tryTorus(vector<Vec3>&V, vector<Face>&F){
    if(N<5000) return false;
    for(int ax=0;ax<3;ax++) if(tryTorusAxis(ax,V,F)) return true;
    return false;
}

struct Simplifier{
    vector<Vec3> V;
    vector<Face> F;
    vector<char> aliveV, aliveF;
    vector<vector<int>> adj;
    vector<double> err;
    int aliveCnt, faceCnt;
    double cosLimit, areaEps;
    vector<int> markA,markB; int stampA=1,stampB=1;
    struct Cand{double cost; int u,v; bool operator<(const Cand&o)const{return cost>o.cost;}};
    priority_queue<Cand> pq;
    Simplifier(){
        V=Pin; F=Fin; aliveV.assign(N,1); aliveF.assign(M,1); err.assign(N,0); aliveCnt=N; faceCnt=M;
        adj.assign(N,{}); for(int i=0;i<M;i++){adj[F[i].a].push_back(i);adj[F[i].b].push_back(i);adj[F[i].c].push_back(i);}        
        markA.assign(N,0); markB.assign(N,0);
